package com.illusionai.app.core

import android.content.Context

class IllusionCore(private val context: Context) {
    
        private val translationManager = TranslationManager(context)
            private val languageManager = LanguageManager.getInstance(context)
                
                    fun getResponseInUserLanguage(input: String): String {
                            val userPreferredLanguage = languageManager.getUserPreferredLanguage()
                                    val baseResponse = getBaseResponse(input)
                                            
                                                    return if (userPreferredLanguage != "en") {
                                                                translateResponse(baseResponse, userPreferredLanguage)
                                                                        } else {
                                                                                    baseResponse
                                                                                            }
                                                                                                }
                                                                                                    
                                                                                                        private fun getBaseResponse(input: String): String {
                                                                                                                return when {
                                                                                                                            input.contains("hello", ignoreCase = true) || 
                                                                                                                                        input.contains("नमस्ते", ignoreCase = true) ||
                                                                                                                                                    input.contains("hola", ignoreCase = true) -> 
                                                                                                                                                                    "Hello! I'm Illusion. How can I help you see more clearly today?"
                                                                                                                                                                                    
                                                                                                                                                                                                input.contains("help", ignoreCase = true) ||
                                                                                                                                                                                                            input.contains("मदद", ignoreCase = true) ||
                                                                                                                                                                                                                        input.contains("ayuda", ignoreCase = true) -> 
                                                                                                                                                                                                                                        "I'm here to help you examine your perceptions and choose better stories."
                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                    input.contains("fail", ignoreCase = true) ||
                                                                                                                                                                                                                                                                                input.contains("असफल", ignoreCase = true) ||
                                                                                                                                                                                                                                                                                            input.contains("fracaso", ignoreCase = true) -> 
                                                                                                                                                                                                                                                                                                            "The story: 'I am a failure.' The evidence: One outcome. The gap: A single event ≠ your worth."
                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                        input.contains("language", ignoreCase = true) ||
                                                                                                                                                                                                                                                                                                                                                    input.contains("भाषा", ignoreCase = true) ||
                                                                                                                                                                                                                                                                                                                                                                input.contains("idioma", ignoreCase = true) -> 
                                                                                                                                                                                                                                                                                                                                                                                "You can change your response language anytime by saying 'change language' or using the language selector."
                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                            else -> 
                                                                                                                                                                                                                                                                                                                                                                                                                            "I see you're constructing a story about this. Let's examine its foundations together."
                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                            
